const configs = [
  { type: 'beauty_salon', label: 'Salon/Barber' },
  { type: 'car_repair', label: 'Auto Shop' },
  { type: 'plumber', label: 'Plumber' },
  { type: 'electrician', label: 'Electrician' },
  { type: 'general_contractor', label: 'Contractor' }
];

return configs.map(c => ({
  json: {
    type: c.type,
    label: c.label,
    location: '34.7465,-92.2896',
    radius: 20000
  }
}));

const out = [];

for (const item of $input.all()) {
  const results = item.json.results || [];

  for (const place of results) {
    out.push({
      json: {
        place_id: place.place_id,
        name: place.name,
        address: place.vicinity,
        rating: place.rating || 0,
        review_count: place.user_ratings_total || 0
      }
    });
  }
}

return out;

const seen = new Set();
const unique = [];

for (const item of $input.all()) {
  if (!seen.has(item.json.place_id)) {
    seen.add(item.json.place_id);
    unique.push(item);
  }
}

return unique;

const scored = [];

for (const item of $input.all()) {
  const lead = item.json;
  let score = 0;

  if (lead.review_count >= 100) score += 25;
  else if (lead.review_count >= 50) score += 20;
  else if (lead.review_count >= 20) score += 15;

  if (lead.rating >= 4.5) score += 15;
  else if (lead.rating >= 4.0) score += 12;

  if (!lead.address) score += 10;

  lead.score = Math.min(score, 100);

  scored.push({ json: lead });
}

return scored;

const items = $input.all();

const hot = items.filter(i => i.json.score >= 80);
const warm = items.filter(i => i.json.score >= 60);

return [{
  json: {
    total: items.length,
    hot: hot.length,
    warm: warm.length,
    top: hot.slice(0, 5).map(l => ({ name: l.json.name, score: l.json.score }))
  }
}];

